async function monitorThreadBloat(client: OpenAI, threadId: string) {
  const messages = await client.beta.threads.messages.list(threadId);
  const messageCount = messages.data.length;

  // Rough token estimation: 4 tokens per word, avg 10 words per message
  const estimatedTokens = messageCount * 40;
  const TOKEN_LIMIT = 128000;

  if (estimatedTokens > TOKEN_LIMIT * 0.9) {
    console.warn(`Thread ${threadId} at ${Math.round(estimatedTokens/1000)}k tokens (${messageCount} messages)`);
    return {
      bloat: true,
      usage: estimatedTokens,
      messages: messageCount,
      action: 'PRUNE_REQUIRED'
    };
  }
  return { bloat: false };
}

