def create_coordination_hub(client, orchestrator_thread):
    '''Single source of truth for all agent coordination'''

    def broadcast_to_specialists(message, specialist_threads):
        for thread_id in specialist_threads:
            client.beta.threads.messages.create(
                thread_id=thread_id,
                role='user',
                content=f"ORCHESTRATOR UPDATE: {message}"
            )
            # Trigger run in each specialist
            client.beta.threads.runs.create(thread_id, assistant_id=SPECIALIST_ASSISTANT_ID)

    def collect_responses(specialist_threads, timeout=300):
        responses = {}
        for thread_id in specialist_threads:
            run = client.beta.threads.runs.create(thread_id, assistant_id=SPECIALIST_ASSISTANT_ID)
            run = client.beta.threads.runs.wait(thread_id, run.id, timeout)
            messages = client.beta.threads.messages.list(thread_id)
            responses[thread_id] = messages.data[0].content[0].text.value
        return responses

    return {
        'broadcast': broadcast_to_specialists,
        'collect': collect_responses,
        'thread': orchestrator_thread
    }

import json
import os
import time
from pathlib import Path

class AtomicState:
    def __init__(self, state_file='agent_state.json'):
        self.state_file = Path(state_file)
        self.lock_file = Path(state_file + '.lock')

    def update_state(self, update):
        timeout = 30
        start = time.time()

        while self.lock_file.exists() and (time.time() - start < timeout):
            time.sleep(0.1)

        if self.lock_file.exists():
            raise TimeoutError('State lock timeout')

        # Atomic write with lock
        self.lock_file.touch()
        try:
            state = {}
            if self.state_file.exists():
                state = json.loads(self.state_file.read_text())
            state.update(update)
            self.state_file.write_text(json.dumps(state, indent=2))
        finally:
            self.lock_file.unlink(missing_ok=True)

app.post('/run-complete', async (req, res) => {
  const { thread_id, run_id, status } = req.body;

  if (status === 'completed') {
    const client = new OpenAI();

    // Get final messages
    const messages = await client.beta.threads.messages.list(thread_id, {
      limit: 5
    });

    const finalMessage = messages.data[0];
    const stateUpdate = {
      thread: thread_id,
      run: run_id,
      completed_at: new Date().toISOString(),
      summary: finalMessage.content[0].text.value.slice(0, 500),
      status: 'completed'
    };

    // Broadcast to all coordination threads
    const coordThreads = ['thread_123', 'thread_456']; // From config
    for (const coordThread of coordThreads) {
      await client.beta.threads.messages.create(coordThread, {
        role: 'user',
        content: `STATE UPDATE: ${JSON.stringify(stateUpdate)}`
      });
    }
  }

  res.json({ received: true });
});

