def check_coordination_health(run_events: list) -> Verification:
    # Detect duplicate function calls
    func_calls = []
    for event in run_events:
        for tool in event.get('required_action', {}).get('tool_calls', []):
            func_calls.append({
                'name': tool['function']['name'],
                'thread': event['thread_id'],
                'time': event['created']
            })

    duplicates = find_duplicates(func_calls, window=300)

